// Cross-partition deduplication registry for emails. Holds exactly one row per (org_id, message_id) pair. This table exists as a separate, unpartitioned relation because Postgres requires the partition key (fetched_at) to participate in any UNIQUE constraint on the partitioned emails table, making it impossible to enforce uniqueness across partition boundaries with a constraint on emails alone. The Go ingestion layer must attempt INSERT … ON CONFLICT DO NOTHING here before inserting into emails; a zero-rows-affected result indicates a duplicate that should be discarded. Emails with a NULL message_id are NOT registered in this table — the ingestion layer must apply content-hash (SHA-256 of headers + body) deduplication for those messages. Do NOT backfill this table inside a migration; use a dedicated backfill job that can run safely against live traffic.
type EmailIdentity struct {
	// Organisation that owns this email. NOT NULL is enforced here even though emails.org_id is still nullable pending a full backfill. A row must not be registered in email_identities until its corresponding emails row has org_id set.
	OrgID int64 `db:"org_id" json:"org_id"`
	// The RFC 5322 Message-ID header value, stored verbatim (angle brackets included if present). Combined with org_id, this is the deduplication key. NULL message_ids are excluded — see table comment.
	MessageID string `db:"message_id" json:"message_id"`
	// emails.internal_id of the canonical (first-seen) copy of this message. Used by the ingestion layer to surface the existing row to the caller when a duplicate is detected.
	InternalID int64 `db:"internal_id" json:"internal_id"`
	// emails.fetched_at of the canonical copy. Stored alongside internal_id so the caller can reconstruct the composite partition key (internal_id, fetched_at) needed to query the partitioned emails table.
	FetchedAt pgtype.Timestamptz `db:"fetched_at" json:"fetched_at"`
	// Timestamp when this identity row was first inserted. Corresponds to the ingestion time of the canonical email copy.
	CreatedAt pgtype.Timestamptz `db:"created_at" json:"created_at"`
}

