// Append-only event log of rule firings. Each row records a single rule evaluation that contributed to an entity's risk score at a specific point in time. Rows are never updated or soft-deleted. Do NOT add a deleted_at column — the full firing history is required for score explainability and rule tuning.
type RuleHit struct {
	ID int64 `db:"id" json:"id"`
	// References the rule that fired.  ON DELETE SET NULL preserves the hit row (and its denormalized rule_version / score_impact snapshots) even after the parent rule is archived or deleted.  A NULL rule_id indicates that the original rule row no longer exists.
	RuleID pgtype.Int8 `db:"rule_id" json:"rule_id"`
	// Point-in-time snapshot of rules.version at the moment this hit was recorded.  Denormalized intentionally so that the firing context is preserved even if the parent rules row is later versioned or archived.  Must not be updated after insert.
	RuleVersion string         `db:"rule_version" json:"rule_version"`
	EntityType  EntityTypeEnum `db:"entity_type" json:"entity_type"`
	EntityID    int64          `db:"entity_id" json:"entity_id"`
	// Point-in-time snapshot of rules.score_impact at the moment this hit was recorded.  Denormalized intentionally so that historical risk scores remain stable and explainable even after the rule is re-tuned.  Must not be updated after insert.
	ScoreImpact int32              `db:"score_impact" json:"score_impact"`
	MatchDetail []byte             `db:"match_detail" json:"match_detail"`
	FiredAt     pgtype.Timestamptz `db:"fired_at" json:"fired_at"`
	OrgID       pgtype.Int8        `db:"org_id" json:"org_id"`
	// The fetched_at timestamp from the emails table when entity_type = 'email'. Required to reconstruct the full composite PK (internal_id, fetched_at) of the partitioned emails table. NULL until backfilled from the application layer. Must be populated by all new inserts where entity_type = 'email'.
	EmailFetchedAt pgtype.Timestamptz `db:"email_fetched_at" json:"email_fetched_at"`
}

// Canonical set of lowercase threat_type values.  The trg_normalise_threat_type triggers on enriched_threats and campaigns reject any value not present in this table.  To add a new threat type, INSERT INTO threat_type_values(value) VALUES ('my_new_type') before inserting rows that use it.
type ThreatTypeValue struct {
	Value string `db:"value" json:"value"`
}

// Normalised store for raw threat-intelligence feed indicators.  These rows are ingested cheaply from external TI feeds and are used only for matching against email-extracted URLs / domains / IPs / hashes.  They carry no enrichment data (no WHOIS, geo, ASN, cert, VT results, etc.). Enrichment happens only in enriched_threats, which is reserved for URL/domain/IP artefacts actually observed through the email pipeline.  Relationship: email_urls → enriched_threats (email observation + enrichment);               email_urls → ti_indicators via email_url_ti_matches (TI matching).
type TiIndicator struct {
	ID            int64           `db:"id" json:"id"`
	FeedID        int64           `db:"feed_id" json:"feed_id"`
	IndicatorType TiIndicatorType `db:"indicator_type" json:"indicator_type"`
	// Canonical normalised representation of the indicator.  For urls: lowercased, scheme-normalised.  For domains: lowercased FQDN, no trailing dot.  For ip: canonical address text (inet_norm form).  For cidr: standard CIDR notation.  For hash: lowercase hex prefixed with algorithm, e.g. sha256:abc123….  For email_address: lower(address).
	IndicatorValue string      `db:"indicator_value" json:"indicator_value"`
	ThreatType     pgtype.Text `db:"threat_type" json:"threat_type"`
	BrandID        pgtype.Int8 `db:"brand_id" json:"brand_id"`
	// DEPRECATED in favour of brand_id (brands table, migration 020).  Populated only when migrating legacy enriched_threats rows that carried a target_brand value.  New ingest must populate brand_id.
	TargetBrand pgtype.Text        `db:"target_brand" json:"target_brand"`
	ThreatTags  []string           `db:"threat_tags" json:"threat_tags"`
	SourceID    pgtype.Text        `db:"source_id" json:"source_id"`
	FirstSeen   pgtype.Timestamptz `db:"first_seen" json:"first_seen"`
	LastSeen    pgtype.Timestamptz `db:"last_seen" json:"last_seen"`
	Confidence  pgtype.Float8      `db:"confidence" json:"confidence"`
	// Feed-assigned severity score [0, 100].  Used for TI-side matching and prioritisation only.  Not aggregated into the main email/threat enrichment risk scoring model.
	RiskScore   int32              `db:"risk_score" json:"risk_score"`
	IsActive    bool               `db:"is_active" json:"is_active"`
	RawMetadata []byte             `db:"raw_metadata" json:"raw_metadata"`
	CreatedAt   pgtype.Timestamptz `db:"created_at" json:"created_at"`
	UpdatedAt   pgtype.Timestamptz `db:"updated_at" json:"updated_at"`
}

type User struct {
	ID int64 `db:"id" json:"id"`
	// Organisation the user belongs to.  ON DELETE RESTRICT prevents accidental cascading deletion of user rows (and the downstream SET NULL on verdicts.created_by) when an org is removed.  Always soft-delete organisations; the application retention reaper handles the eventual hard-delete after all child rows are cleaned up.
	OrgID int64 `db:"org_id" json:"org_id"`
	// User e-mail address. The constraint chk_users_email_format enforces a minimal structural format only (local-part@domain.tld, no whitespace). Full RFC-5321/5322 validation, MX lookup, and disposable-address detection are the application layer's responsibility.
	Email        string             `db:"email" json:"email"`
	DisplayName  pgtype.Text        `db:"display_name" json:"display_name"`
	Role         UserRole           `db:"role" json:"role"`
	PasswordHash pgtype.Text        `db:"password_hash" json:"password_hash"`
	LastLoginAt  pgtype.Timestamptz `db:"last_login_at" json:"last_login_at"`
	DeletedAt    pgtype.Timestamptz `db:"deleted_at" json:"deleted_at"`
	CreatedAt    pgtype.Timestamptz `db:"created_at" json:"created_at"`
	UpdatedAt    pgtype.Timestamptz `db:"updated_at" json:"updated_at"`
}

// Canonical set of allowed API key scope strings.  The trg_validate_api_key_scopes trigger on api_keys rejects any scope value not present in this table.  To add a new scope, INSERT INTO valid_api_scopes(value) VALUES ('resource:action') before creating keys that use it.
type ValidApiScope struct {
	Value string `db:"value" json:"value"`
}

// Append-only event log of entity verdicts. Rows are never updated or soft-deleted. The current verdict for an entity is derived by selecting the latest row by created_at (see the current_verdicts view). Do NOT add a deleted_at column — historical verdicts must be retained for auditability.
type Verdict struct {
	ID           int64              `db:"id" json:"id"`
	EntityType   EntityTypeEnum     `db:"entity_type" json:"entity_type"`
	EntityID     int64              `db:"entity_id" json:"entity_id"`
	Label        VerdictLabel       `db:"label" json:"label"`
	Confidence   pgtype.Float8      `db:"confidence" json:"confidence"`
	Source       VerdictSource      `db:"source" json:"source"`
	ModelVersion pgtype.Text        `db:"model_version" json:"model_version"`
	Notes        pgtype.Text        `db:"notes" json:"notes"`
	CreatedAt    pgtype.Timestamptz `db:"created_at" json:"created_at"`
	// References users(id) with ON DELETE SET NULL. If a user row is hard-deleted, this column is set to NULL and analyst attribution for the verdict is permanently lost. To preserve attribution, always soft-delete users (SET deleted_at = NOW()) instead of hard-deleting them. The BEFORE DELETE trigger on users emits a WARNING when a hard delete is attempted on a non-soft-deleted row.
	CreatedBy pgtype.Int8 `db:"created_by" json:"created_by"`
	OrgID     pgtype.Int8 `db:"org_id" json:"org_id"`
	// The fetched_at timestamp from the emails table when entity_type = 'email'. Required to reconstruct the full composite PK (internal_id, fetched_at) of the partitioned emails table. NULL until backfilled from the application layer. Must be populated by all new inserts where entity_type = 'email'.
	EmailFetchedAt pgtype.Timestamptz `db:"email_fetched_at" json:"email_fetched_at"`
}
